// 极简 Markdown 渲染器（够用即可，不依赖外部库）
// 支持：标题、粗斜体、链接、图片、行内代码、代码块、列表、引用、分割线、段落、html 透传
(function (global) {
  function escapeHtml(s) {
    return s.replace(/[&<>"']/g, (c) => ({ '&': '&amp;', '<': '&lt;', '>': '&gt;', '"': '&quot;', "'": '&#39;' }[c]));
  }
  function inline(text) {
    let s = text;
    // 代码（最先处理避免被其他规则破坏）
    s = s.replace(/`([^`\n]+?)`/g, (_, c) => `<code>${escapeHtml(c)}</code>`);
    // 图片
    s = s.replace(/!\[([^\]]*)\]\(([^)\s]+)(?:\s+"([^"]*)")?\)/g, (_, alt, url, t) => `<img alt="${escapeHtml(alt)}" src="${escapeHtml(url)}"${t ? ` title="${escapeHtml(t)}"` : ''}>`);
    // 链接
    s = s.replace(/\[([^\]]+)\]\(([^)\s]+)(?:\s+"([^"]*)")?\)/g, (_, txt, url, t) => `<a href="${escapeHtml(url)}" target="_blank" rel="noopener"${t ? ` title="${escapeHtml(t)}"` : ''}>${txt}</a>`);
    // 粗体
    s = s.replace(/\*\*([^*\n]+?)\*\*/g, '<strong>$1</strong>');
    // 斜体
    s = s.replace(/(^|[^*])\*([^*\n]+?)\*/g, '$1<em>$2</em>');
    // 删除线
    s = s.replace(/~~([^~\n]+?)~~/g, '<del>$1</del>');
    return s;
  }
  function render(md) {
    if (!md) return '';
    const lines = md.replace(/\r\n/g, '\n').split('\n');
    const out = [];
    let i = 0;
    while (i < lines.length) {
      const line = lines[i];
      // 代码块
      const fence = line.match(/^```(\w*)\s*$/);
      if (fence) {
        const lang = fence[1] || '';
        i++;
        const code = [];
        while (i < lines.length && !/^```\s*$/.test(lines[i])) {
          code.push(lines[i]);
          i++;
        }
        i++;
        out.push(`<pre><code class="language-${escapeHtml(lang)}">${escapeHtml(code.join('\n'))}</code></pre>`);
        continue;
      }
      // 标题
      const h = line.match(/^(#{1,6})\s+(.*)$/);
      if (h) {
        const lvl = h[1].length;
        out.push(`<h${lvl}>${inline(escapeHtml(h[2]))}</h${lvl}>`);
        i++;
        continue;
      }
      // 分割线
      if (/^---+\s*$/.test(line) || /^\*\*\*+\s*$/.test(line)) {
        out.push('<hr>');
        i++;
        continue;
      }
      // 引用
      if (/^>\s?/.test(line)) {
        const block = [];
        while (i < lines.length && /^>\s?/.test(lines[i])) {
          block.push(lines[i].replace(/^>\s?/, ''));
          i++;
        }
        out.push(`<blockquote>${inline(escapeHtml(block.join('\n'))).replace(/\n/g, '<br>')}</blockquote>`);
        continue;
      }
      // 无序列表
      if (/^[-*]\s+/.test(line)) {
        const items = [];
        while (i < lines.length && /^[-*]\s+/.test(lines[i])) {
          items.push(lines[i].replace(/^[-*]\s+/, ''));
          i++;
        }
        out.push(`<ul>${items.map((x) => `<li>${inline(escapeHtml(x))}</li>`).join('')}</ul>`);
        continue;
      }
      // 有序列表
      if (/^\d+\.\s+/.test(line)) {
        const items = [];
        while (i < lines.length && /^\d+\.\s+/.test(lines[i])) {
          items.push(lines[i].replace(/^\d+\.\s+/, ''));
          i++;
        }
        out.push(`<ol>${items.map((x) => `<li>${inline(escapeHtml(x))}</li>`).join('')}</ol>`);
        continue;
      }
      // 空行
      if (line.trim() === '') {
        i++;
        continue;
      }
      // 段落（合并连续非空行）
      const para = [];
      while (i < lines.length && lines[i].trim() !== '' && !/^(#{1,6}\s|>\s|[-*]\s|\d+\.\s|```|---|\*\*\*)/.test(lines[i])) {
        para.push(lines[i]);
        i++;
      }
      if (para.length) {
        out.push(`<p>${inline(escapeHtml(para.join(' ')))}</p>`);
      }
    }
    return out.join('\n');
  }
  global.marked = { parse: render };
})(window);
